declare(strict_types=1);require_once __DIR__.'/../app/email_marketing.php';proteger_admin();$pdo=getPDO();email_marketing_ensure_schema($pdo);$s=email_settings($pdo);
$totals=$pdo->query("SELECT COUNT(*) total,SUM(status='sent') sent,SUM(status='delivered') delivered,SUM(status='bounced') bounced,SUM(status='complaint') complaints,SUM(first_opened_at IS NOT NULL) opened,SUM(first_clicked_at IS NOT NULL) clicked,SUM(status='unsubscribed') unsubscribed FROM email_messages")->fetch(PDO::FETCH_ASSOC)?:[];$supp=(int)$pdo->query('SELECT COUNT(DISTINCT email) FROM email_suppressions WHERE active=1')->fetchColumn();$recent=$pdo->query("SELECT m.*,u.nome FROM email_messages m LEFT JOIN users u ON u.id=m.user_id ORDER BY m.id DESC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC)?:[];$menu='email_marketing';$page_title='E-mail marketing';include __DIR__.'/_header.php';echo email_admin_styles();
function em_pct($a,$b):string{return $b>0?number_format(100*$a/$b,1,',','.').'%':'0,0%';}
?><div class="em"><div class="em-head"><div><h1>E-mail marketing</h1><p class="text-muted">Campanhas, automações e saúde de entrega pelo Amazon SES.</p></div><a class="btn btn-primary" href="email_campanhas.php?new=1">+ Nova campanha</a></div><?=email_admin_nav('dashboard')?>
<div class="em-card <?=$s['engine_enabled']==='1'?'em-ok':'em-bad'?>">Motor: <strong><?=$s['engine_enabled']==='1'?'ativo':'pausado'?></strong> · Região <?=email_h($s['region'])?> · Remetente <?=email_h($s['from_email']?:'não configurado')?> <a href="email_config.php">Configurar</a></div>
<div class="em-grid"><?php foreach([['sent','Aceitos pelo SES'],['delivered','Entregues'],['opened','Aberturas únicas'],['clicked','Cliques únicos'],['bounced','Bounces'],['complaints','Reclamações'],['unsubscribed','Descadastros']] as [$k,$l]):?><div class="em-card em-kpi"><small><?=email_h($l)?></small><strong><?=number_format((int)($totals[$k]??0),0,',','.')?></strong><span class="text-muted"><?=in_array($k,['delivered','bounced'],true)?em_pct((int)($totals[$k]??0),(int)($totals['sent']??0)):em_pct((int)($totals[$k]??0),(int)($totals['delivered']??0))?></span></div><?php endforeach?><div class="em-card em-kpi"><small>Suprimidos ativos</small><strong><?=number_format($supp,0,',','.')?></strong><a href="email_contatos.php">Ver lista</a></div></div>
<section class="em-card"><h2>Envios recentes</h2><div class="em-table"><table><thead><tr><th>Data</th><th>Aluno</th><th>Assunto</th><th>Status</th><th>Entrega</th><th>Abertura</th><th>Clique</th></tr></thead><tbody><?php foreach($recent as $r):?><tr><td><?=email_h(date('d/m/Y H:i',strtotime($r['created_at'])))?></td><td><?=email_h($r['nome']?:$r['recipient_email'])?></td><td><?=email_h($r['subject'])?></td><td><span class="em-pill"><?=email_h($r['status'])?></span></td><td><?=$r['delivered_at']?'Sim':'-'?></td><td><?=$r['first_opened_at']?'Sim':'-'?></td><td><?=$r['first_clicked_at']?'Sim':'-'?></td></tr><?php endforeach?><?php if(!$recent):?><tr><td colspan="7" class="text-muted">Nenhum envio registrado.</td></tr><?php endif?></tbody></table></div></section></div><?php include __DIR__.'/_footer.php';
